passthrough_wrapper_v2_1.code_snippet:
// 1. Declare mock с DAP_MOCK_CONFIG_PASSTHROUGH
DAP_MOCK_DECLARE(dap_http_simple_reply, DAP_MOCK_CONFIG_PASSTHROUGH);

// 2. Create универсальный wrapper с DAP_MOCK_WRAPPER_PASSTHROUGH
DAP_MOCK_WRAPPER_PASSTHROUGH(size_t, dap_http_simple_reply,
    (dap_http_simple_t *a_http_simple, void *a_data, size_t a_data_size),
    (a_http_simple, a_data, a_data_size))

// Готово! Mock автоматически:
// - Вызывает __real_dap_http_simple_reply() (call_original_before=true)
// - Записывает вызов через dap_mock_record_call()
// - Возвращает результат оригинальной функции

// 3. В тесте проверяем call count
void test_http_request(void) {
    // ... HTTP request ...

    // Verify that reply was called
    TEST_ASSERT(DAP_MOCK_GET_CALL_COUNT(dap_http_simple_reply) == 1,
               "HTTP reply should be called once");
}

async_mock_example.code_snippet:
// Declare async mock с задержкой
DAP_MOCK_DECLARE(dap_client_http_request, {
    .return_value = {0},
    .delay = {.type = DAP_MOCK_DELAY_FIXED, .fixed_us = 500000},  // 500ms
    .async = true     // Execute in thread pool
});

void test_concurrent_requests(void) {
    // Configure thread pool
    dap_mock_settings_t l_settings = {
        .async_worker_threads = 8,
        .logging_enabled = true
    };
    dap_mock_apply_settings(&l_settings);

    // Start multiple async requests
    for (int i = 0; i < 10; i++) {
        start_http_request();
    }

    // Wait for completion with intelligent check
    dap_test_async_config_t l_config = {.timeout_ms = 10000, .check_interval_ms = 100};
    TEST_ASSERT(dap_test_wait_condition(
        []{ return DAP_MOCK_GET_CALL_COUNT(dap_client_http_request) == 10; },
        &l_config
    ), "All requests should complete");
}

spy_pattern.code:
DAP_MOCK_DECLARE(critical_function, {
    .call_original_before = true  // Call first, then track
});
DAP_MOCK_WRAPPER_PASSTHROUGH(int, critical_function, (int a), (a))

// Function behaves normally, но мы можем проверить вызовы
TEST_ASSERT(DAP_MOCK_GET_CALL_COUNT(critical_function) > 0, "Should be called");

parameter_spy.code:
DAP_MOCK_DECLARE(sensitive_func, {
    .call_original_before = true
});

void test_check_params(void) {
    my_code_that_calls_sensitive_func("secret", 123);

    // Verify parameters passed to sensitive function
    void **l_args = dap_mock_get_call_args(g_mock_sensitive_func, 0);
    TEST_ASSERT(strcmp((char*)l_args[0], "secret") == 0, "Correct string");
    TEST_ASSERT((int)(intptr_t)l_args[1] == 123, "Correct number");
}

